function getSession(sid) {
  const s = sessions.get(sid);
  if (!s) return null;
  if (now() - s.lastSeenAt > SESSION_TTL_MS) {
    sessions.delete(sid);
    return null;
  }
  s.lastSeenAt = now();
  return s;
}

